## Task: Replace TestController with FilesController exposing all endpoints
## Step: write-tests

### Controllers/TestController.cs
```cs
using Microsoft.AspNetCore.Mvc;

namespace TestProject.Controllers {
    [ApiController]
    [Route("[controller]")]
    public class TestController : ControllerBase {

        private readonly ILogger<TestController> _logger;

        public TestController(ILogger<TestController> logger) {
            _logger = logger;
        }

        [HttpGet]
        public string Get() {
            return "API Response";
        }
    }
}
```
DELETE Controllers/TestController.cs and CREATE Controllers/FilesController.cs (namespace `TestProject.Controllers`). Use `[ApiController]` and `[Route("api/[controller]")]` (routes resolve under /api/files). Constructor injects `TestProject.Services.IFileService _service` (and an optional ILogger<FilesController>). Bring in `using TestProject.Models;` and `using TestProject.Services;`. Endpoints:
- `[HttpGet("browse")] ActionResult<BrowseResultDto> Browse([FromQuery] string? path) => Ok(_service.Browse(path ?? ""));`
- `[HttpGet("search")] ActionResult<SearchResultDto> Search([FromQuery] string query, [FromQuery] string? path) => Ok(_service.Search(query ?? "", path ?? ""));`
- `[HttpPost("upload")] async Task<IActionResult> Upload([FromQuery] string? path, [FromForm] IFormFile file) => await _service.UploadAsync(path ?? "", file); return Ok(new { path = string.IsNullOrEmpty(path) ? file.FileName : $"{path}/{file.FileName}" });`
- `[HttpGet("download")] IActionResult Download([FromQuery] string path)`: resolve `var full = _service.ResolveFullPath(path);`, derive content type via `new Microsoft.AspNetCore.StaticFiles.FileExtensionContentTypeProvider().TryGetContentType(full, out var ct) ? ct : "application/octet-stream";`, then `return PhysicalFile(full, ct, Path.GetFileName(full));`
- `[HttpDelete("delete")] IActionResult Delete([FromQuery] string path) => wrap in try/catch; _service.Delete(path); return Ok(new { success = true });`
- `[HttpPost("move")] IActionResult Move([FromBody] MoveRequest request) => _service.Move(request); return Ok(new { success = true });`
- `[HttpPost("copy")] IActionResult Copy([FromBody] CopyRequest request) => _service.Copy(request); return Ok(new { success = true });`
Wrap each service call body in try/catch for `ArgumentException`, `UnauthorizedAccessException`, `DirectoryNotFoundException`, `FileNotFoundException`, `IOException` and return `BadRequest(new { error = ex.Message })`. Verify: `dotnet build`; then `dotnet run` and `curl -sk "https://localhost:7146/api/files/browse?path="` returns JSON with Entries/FolderCount/FileCount/TotalSize.

using Microsoft.AspNetCore.Mvc;

namespace TestProject.Controllers {
    [ApiController]
    [Route("[controller]")]
    public class TestController : ControllerBase {

        private readonly ILogger<TestController> _logger;

        public TestController(ILogger<TestController> logger) {
            _logger = logger;
        }

        [HttpGet]
        public string Get() {
            return "API Response";
        }
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary.
    /// </summary>
    Task UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);
}

using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Options;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Path-safe implementation of <see cref="IFileService"/> that confines every
/// operation to a single home directory computed once at construction time.
/// Any relative path that normalizes to a location outside the home root causes
/// an <see cref="ArgumentException"/> to be thrown before any disk access.
/// </summary>
public sealed class FileService : IFileService
{
    private const int MaxSearchResults = 500;

    private readonly string _root;

    public FileService(IOptions<FileServiceOptions> options, IWebHostEnvironment env)
    {
        var root = Path.GetFullPath(Path.Combine(env.ContentRootPath, options.Value.HomeDirectory ?? "Home"));
        Directory.CreateDirectory(root);
        _root = root;
    }

    // =====================================================================
    // IFileService
    // =====================================================================

    /// <inheritdoc />
    public BrowseResultDto Browse(string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var directoryPaths = Directory.GetDirectories(full);
        var filePaths = Directory.GetFiles(full);

        var entries = new List<FileEntryDto>(directoryPaths.Length + filePaths.Length);

        foreach (var dir in directoryPaths)
        {
            var info = new DirectoryInfo(dir);
            entries.Add(new FileEntryDto(
                Name: info.Name,
                Path: ToRelative(dir),
                IsDirectory: true,
                Size: 0,
                LastModified: info.LastWriteTimeUtc));
        }

        foreach (var file in filePaths)
        {
            var info = new FileInfo(file);
            entries.Add(new FileEntryDto(
                Name: info.Name,
                Path: ToRelative(file),
                IsDirectory: false,
                Size: info.Length,
                LastModified: info.LastWriteTimeUtc));
        }

        // Directories first, then files, each group sorted by name (OrdinalIgnoreCase).
        entries.Sort(CompareEntries);

        var folderCount = 0;
        var fileCount = 0;
        var totalSize = 0L;
        foreach (var entry in entries)
        {
            if (entry.IsDirectory)
            {
                folderCount++;
            }
            else
            {
                fileCount++;
                totalSize += entry.Size;
            }
        }

        var parent = ComputeParent(relative);

        return new BrowseResultDto(relative, parent, entries, folderCount, fileCount, totalSize);
    }

    /// <inheritdoc />
    public SearchResultDto Search(string query, string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var results = new List<FileEntryDto>(MaxSearchResults);

        var stack = new Stack<string>();
        stack.Push(full);

        while (stack.Count > 0 && results.Count < MaxSearchResults)
        {
            var current = stack.Pop();

            string[] subdirectories;
            string[] files;
            try
            {
                subdirectories = Directory.GetDirectories(current);
                files = Directory.GetFiles(current);
            }
            catch (UnauthorizedAccessException)
            {
                continue;
            }
            catch (DirectoryNotFoundException)
            {
                continue;
            }

            foreach (var dir in subdirectories)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new DirectoryInfo(dir);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(dir),
                        IsDirectory: true,
                        Size: 0,
                        LastModified: info.LastWriteTimeUtc));
                }

                stack.Push(dir);
            }

            foreach (var file in files)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new FileInfo(file);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(file),
                        IsDirectory: false,
                        Size: info.Length,
                        LastModified: info.LastWriteTimeUtc));
                }
            }
        }

        return new SearchResultDto(query, relative, results);
    }

    /// <inheritdoc />
    public string ResolveFullPath(string relativePath) => SafeResolve(relativePath);

    /// <inheritdoc />
    public async Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        var dir = SafeResolve(relativeDirPath);
        Directory.CreateDirectory(dir);

        var path = Path.Combine(dir, file.FileName);
        await using var fs = File.Create(path);
        await file.CopyToAsync(fs);
    }

    /// <inheritdoc />
    public void Delete(string relativePath)
    {
        var path = SafeResolve(relativePath);

        if (Directory.Exists(path))
        {
            Directory.Delete(path, recursive: true);
        }
        else
        {
            File.Delete(path);
        }
    }

    /// <inheritdoc />
    public void Move(MoveRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        Directory.CreateDirectory(Path.GetDirectoryName(destination)!);

        if (Directory.Exists(source))
        {
            Directory.Move(source, destination);
        }
        else
        {
            File.Move(source, destination);
        }
    }

    /// <inheritdoc />
    public void Copy(CopyRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        if (Directory.Exists(source))
        {
            CopyDirectory(source, destination);
        }
        else
        {
            File.Copy(source, destination, overwrite: false);
        }
    }

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Combines the home root with <paramref name="relativePath"/>, normalizes
    /// the result, and verifies it stays within the root. A null, empty, or
    /// whitespace path resolves to the root itself. Anything that escapes the
    /// root throws <see cref="ArgumentException"/>.
    /// </summary>
    private string SafeResolve(string relativePath)
    {
        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return _root;
        }

        var full = Path.GetFullPath(Path.Combine(_root, relativePath));

        var isRoot = string.Equals(full, _root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(_root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Converts an absolute path inside the root to a forward-slash relative
    /// path. The root itself becomes the empty string.
    /// </summary>
    private string ToRelative(string full)
    {
        return full
            .Substring(_root.Length)
            .TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
            .Replace('\\', '/');
    }

    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    private static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        var separatorIndex = relative.LastIndexOf('/');
        if (separatorIndex < 0)
        {
            return string.Empty;
        }

        return relative.Substring(0, separatorIndex);
    }

    /// <summary>
    /// Sorts directories before files, ordering each group by name using
    /// <see cref="StringComparison.OrdinalIgnoreCase"/>.
    /// </summary>
    private static int CompareEntries(FileEntryDto a, FileEntryDto b)
    {
        if (a.IsDirectory != b.IsDirectory)
        {
            return a.IsDirectory ? -1 : 1;
        }

        return string.Compare(a.Name, b.Name, StringComparison.OrdinalIgnoreCase);
    }

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten, matching the no-overwrite contract of
    /// <see cref="File.Copy(string, string, bool)"/>.
    /// </summary>
    private static void CopyDirectory(string source, string destination)
    {
        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)));
        }
    }
}

using System.Collections.Generic;

namespace TestProject.Models;

public sealed record FileEntryDto(string Name, string Path, bool IsDirectory, long Size, System.DateTime LastModified);

public sealed record BrowseResultDto(string Path, string? Parent, IReadOnlyList<FileEntryDto> Entries, int FolderCount, int FileCount, long TotalSize);

public sealed record SearchResultDto(string Query, string Path, IReadOnlyList<FileEntryDto> Results);

public sealed record MoveRequest(string SourcePath, string DestinationPath);

public sealed record CopyRequest(string SourcePath, string DestinationPath);

using System;
using TestProject;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Tests for <see cref="FileServiceOptions"/>, the strongly typed options
/// object that configures the server side home directory.
/// </summary>
public class FileServiceOptionsTests
{
    [Fact]
    public void Constructor_DefaultHomeDirectory_IsHome()
    {
        var options = new FileServiceOptions();

        Assert.Equal("Home", options.HomeDirectory);
    }

    [Fact]
    public void HomeDirectory_IsMutable()
    {
        var options = new FileServiceOptions();

        options.HomeDirectory = "/var/data/files";

        Assert.Equal("/var/data/files", options.HomeDirectory);
    }

    [Theory]
    [InlineData("MyFiles")]
    [InlineData("")]
    [InlineData("   ")]
    public void HomeDirectory_CanBeSetToArbitraryStringValue(string value)
    {
        var options = new FileServiceOptions();

        options.HomeDirectory = value;

        Assert.Equal(value, options.HomeDirectory);
    }

    [Fact]
    public void HomeDirectory_IsAStringProperty()
    {
        var property = typeof(FileServiceOptions).GetProperty(nameof(FileServiceOptions.HomeDirectory));

        Assert.NotNull(property);
        Assert.Equal(typeof(string), property!.PropertyType);
        Assert.True(property.CanRead);
        Assert.True(property.CanWrite);
    }

    [Fact]
    public void FileServiceOptions_IsAPublicClass_InTestProjectNamespace()
    {
        var type = typeof(FileServiceOptions);

        Assert.True(type.IsClass);
        Assert.True(type.IsPublic);
        Assert.Equal("TestProject", type.Namespace);
    }
}

namespace TestProject;

public class FileServiceOptions
{
    public string HomeDirectory { get; set; } = "Home";
}

namespace TestProject {
    public class Program {
        public static void Main(string[] args) {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.

            builder.Services.AddControllers();

            var app = builder.Build();

            // Configure the HTTP request pipeline.

            app.UseHttpsRedirection();

            app.UseStaticFiles();

            app.MapControllers();

            app.Run();
        }
    }
}

using System.Text;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Models;
using TestProject.Services;
using Xunit;

namespace TestProject.Tests.Services;

/// <summary>
/// Functional tests for <see cref="FileService"/>. Each test runs against a
/// unique temporary content root so that tests are fully independent and
/// never touch the real file system outside a scratch directory.
///
/// The service computes its home root once, at construction time, as
/// <c>Path.GetFullPath(Path.Combine(env.ContentRootPath, options.HomeDirectory))</c>
/// and is expected to create that directory if it does not yet exist. Every
/// operation must funnel inputs through a path-safety check so that paths
/// escaping the home root throw <see cref="ArgumentException"/>.
/// </summary>
public class FileServiceTests : IDisposable
{
    private readonly string _contentRoot;

    public FileServiceTests()
    {
        _contentRoot = Directory.CreateTempSubdirectory("fs_test_").FullName;
    }

    public void Dispose()
    {
        try
        {
            Directory.Delete(_contentRoot, recursive: true);
        }
        catch
        {
            // Best effort cleanup; temp dirs may already be gone.
        }
    }

    // Builds a fresh service whose home directory lives under the per-test
    // content root. Returns the absolute, normalized root the service should
    // be treating as its sandbox.
    private (FileService service, string root) CreateService(string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = _contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(_contentRoot, homeDirectory));
        return (service, root);
    }

    private static IFormFile CreateFormFile(string fileName, string content)
    {
        var bytes = Encoding.UTF8.GetBytes(content);
        var stream = new MemoryStream(bytes);
        return new FormFile(stream, 0, bytes.Length, "file", fileName);
    }

    // =====================================================================
    // Constructor / root computation
    // =====================================================================

    [Fact]
    public void Constructor_CreatesRootDirectory_WhenItDoesNotExist()
    {
        var home = "BrandNewHome";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (_, root) = CreateService(home);

        Assert.True(Directory.Exists(root));
        Assert.Equal(expectedRoot, root);
    }

    [Fact]
    public void Constructor_SupportsNestedHomeDirectoryPath()
    {
        var home = "Data/Files";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (_, root) = CreateService(home);

        Assert.Equal(expectedRoot, root);
        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void Constructor_NullHomeDirectory_DefaultsToHome()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
        var options = Options.Create(new FileServiceOptions { HomeDirectory = null! });

        var service = new FileService(options, env);

        var expected = Path.GetFullPath(Path.Combine(_contentRoot, "Home"));
        Assert.Equal(expected, service.ResolveFullPath(""));
        Assert.True(Directory.Exists(expected));
    }

    // =====================================================================
    // ResolveFullPath
    // =====================================================================

    [Fact]
    public void ResolveFullPath_Empty_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath(""));
    }

    [Fact]
    public void ResolveFullPath_Null_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath(null!));
    }

    [Fact]
    public void ResolveFullPath_Whitespace_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath("   "));
    }

    [Fact]
    public void ResolveFullPath_RelativePath_CombinesWithRoot()
    {
        var (service, root) = CreateService();

        var resolved = service.ResolveFullPath(Path.Combine("docs", "a.txt"));

        Assert.Equal(Path.GetFullPath(Path.Combine(root, "docs", "a.txt")), resolved);
        Assert.StartsWith(root + Path.DirectorySeparatorChar, resolved);
    }

    [Theory]
    [InlineData("../escape")]
    [InlineData("../../escape")]
    [InlineData("/etc/passwd")]
    public void ResolveFullPath_PathOutsideRoot_ThrowsArgumentException(string path)
    {
        var (service, _) = CreateService();

        var ex = Assert.Throws<ArgumentException>(() => service.ResolveFullPath(path));
        Assert.Equal("Invalid path", ex.Message);
    }

    [Fact]
    public void ResolveFullPath_DotDotThatStaysInsideRoot_Resolves()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs"));

        // "docs/../a.txt" normalizes back inside the root and must be allowed.
        var resolved = service.ResolveFullPath("docs/../a.txt");

        Assert.Equal(Path.GetFullPath(Path.Combine(root, "a.txt")), resolved);
    }

    // =====================================================================
    // Browse
    // =====================================================================

    [Fact]
    public async Task Browse_Root_ReturnsDirectoriesFirstThenFiles_SortedOrdinalIgnoreCase()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "images"));
        Directory.CreateDirectory(Path.Combine(root, "docs"));
        await File.WriteAllTextAsync(Path.Combine(root, "z.txt"), "ZZ");
        await File.WriteAllTextAsync(Path.Combine(root, "a.txt"), "AAA");

        var result = service.Browse("");

        Assert.Equal("", result.Path);
        Assert.Null(result.Parent);
        Assert.Equal(2, result.FolderCount);
        Assert.Equal(2, result.FileCount);
        Assert.Equal(5L, result.TotalSize);

        Assert.Equal(new[] { "docs", "images", "a.txt", "z.txt" },
            result.Entries.Select(e => e.Name).ToArray());
        Assert.Equal(new[] { true, true, false, false },
            result.Entries.Select(e => e.IsDirectory).ToArray());
    }

    [Fact]
    public async Task Browse_EntryPaths_UseForwardSlashes_AndCorrectMetadata()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs"));
        var filePath = Path.Combine(root, "a.txt");
        await File.WriteAllTextAsync(filePath, "hello");

        var result = service.Browse("");

        var file = result.Entries.Single(e => e.Name == "a.txt");
        Assert.Equal("a.txt", file.Path);
        Assert.False(file.IsDirectory);
        Assert.Equal(5L, file.Size);
        Assert.Equal(new FileInfo(filePath).LastWriteTimeUtc, file.LastModified);

        var dir = result.Entries.Single(e => e.Name == "docs");
        Assert.Equal("docs", dir.Path);
        Assert.True(dir.IsDirectory);
        Assert.Equal(0L, dir.Size);
    }

    [Fact]
    public async Task Browse_Subdirectory_ReturnsRelativePathAndEmptyParent()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs", "deep"));
        await File.WriteAllTextAsync(Path.Combine(root, "docs", "a.txt"), "x");

        var result = service.Browse("docs");

        Assert.Equal("docs", result.Path);
        Assert.Equal("", result.Parent); // parent of "docs" is root -> ""
        Assert.Equal("docs/deep", result.Entries.Single(e => e.Name == "deep").Path);
        Assert.Equal("docs/a.txt", result.Entries.Single(e => e.Name == "a.txt").Path);
    }

    [Fact]
    public void Browse_DeepSubdirectory_ParentIsRelativeParentPath()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs", "deep"));

        var result = service.Browse("docs/deep");

        Assert.Equal("docs/deep", result.Path);
        Assert.Equal("docs", result.Parent);
    }

    [Fact]
    public async Task Browse_CountsAndSize_AreFromCurrentDirectoryOnly()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "sub", "nested")); // nested must not count
        await File.WriteAllTextAsync(Path.Combine(root, "a.txt"), "12"); // size 2
        await File.WriteAllTextAsync(Path.Combine(root, "sub", "b.txt"), "xxxxx"); // excluded

        var result = service.Browse("");

        Assert.Equal(1, result.FolderCount);
        Assert.Equal(1, result.FileCount);
        Assert.Equal(2L, result.TotalSize);
    }

    [Fact]
    public void Browse_NonExistentDirectory_ThrowsDirectoryNotFoundException()
    {
        var (service, _) = CreateService();

        Assert.Throws<DirectoryNotFoundException>(() => service.Browse("does-not-exist"));
    }

    [Fact]
    public void Browse_PathEscapingRoot_ThrowsArgumentException()
    {
        var (service, _) = CreateService();

        Assert.Throws<ArgumentException>(() => service.Browse("../escape"));
    }

    // =====================================================================
    // Search
    // =====================================================================

    [Fact]
    public async Task Search_FindsMatchingEntriesByName_OrdinalIgnoreCase_AndRecursively()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs"));
        await File.WriteAllTextAsync(Path.Combine(root, "Report.txt"), "x");
        await File.WriteAllTextAsync(Path.Combine(root, "docs", "weekly-report.md"), "x");
        await File.WriteAllTextAsync(Path.Combine(root, "notes.txt"), "x");

        var result = service.Search("report", "");

        Assert.Equal("report", result.Query);
        Assert.Equal("", result.Path);
        Assert.Equal(2, result.Results.Count);
        Assert.Contains(result.Results, r => r.Path == "Report.txt");
        Assert.Contains(result.Results, r => r.Path == "docs/weekly-report.md");
        Assert.DoesNotContain(result.Results, r => r.Name == "notes.txt");
    }

    [Fact]
    public async Task Search_LimitsResults_ToGivenRelativePath()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "a"));
        Directory.CreateDirectory(Path.Combine(root, "b"));
        await File.WriteAllTextAsync(Path.Combine(root, "a", "target.txt"), "x");
